import{_ as t,c as o,o as n,a1 as a}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Google Cloud: 多账户配置 | opencode-mystatus","description":"学习 opencode-mystatus 的 Google Cloud 多账户配置方法。支持同时管理多个账户，查看 4 种模型额度，解决单账户额度不足问题。","frontmatter":{"title":"Google Cloud: 多账户配置 | opencode-mystatus","sidebarTitle":"Google Cloud","subtitle":"Google Cloud: 多账户配置","description":"学习 opencode-mystatus 的 Google Cloud 多账户配置方法。支持同时管理多个账户，查看 4 种模型额度，解决单账户额度不足问题。","tags":["Google Cloud","Mehrere Konten verwalten","Antigravity","Modellzuordnung"],"prerequisite":["start-quick-start"],"order":1},"headers":[],"relativePath":"de/vbgate/opencode-mystatus/advanced/google-setup/index.md","filePath":"de/vbgate/opencode-mystatus/advanced/google-setup/index.md"}'),i={name:"de/vbgate/opencode-mystatus/advanced/google-setup/index.md"};function r(d,e,l,s,h,u){return n(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="google-cloud-erweiterte-konfiguration-mehrere-konten-und-modellverwaltung" tabindex="-1">Google Cloud-Erweiterte Konfiguration: Mehrere Konten und Modellverwaltung <a class="header-anchor" href="#google-cloud-erweiterte-konfiguration-mehrere-konten-und-modellverwaltung" aria-label="Permalink to &quot;Google Cloud-Erweiterte Konfiguration: Mehrere Konten und Modellverwaltung&quot;">​</a></h1><h2 id="was-sie-nach-diesem-tutorial-konnen" tabindex="-1">Was Sie nach diesem Tutorial können <a class="header-anchor" href="#was-sie-nach-diesem-tutorial-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Tutorial können&quot;">​</a></h2><p>Mehrere Google Cloud-Konten konfigurieren, mit einem Klick alle Kontokredite anzeigen, die Zuordnungsbeziehung von 4 Modellen (G3 Pro, G3 Image, G3 Flash, Claude) verstehen und das Problem unzureichender Modellkredite eines einzelnen Kontos lösen.</p><h2 id="grundlegende-idee" tabindex="-1">Grundlegende Idee <a class="header-anchor" href="#grundlegende-idee" aria-label="Permalink to &quot;Grundlegende Idee&quot;">​</a></h2><h3 id="mehrere-konten-unterstutzen" tabindex="-1">Mehrere Konten unterstützen <a class="header-anchor" href="#mehrere-konten-unterstutzen" aria-label="Permalink to &quot;Mehrere Konten unterstützen&quot;">​</a></h3><p>opencode-mystatus unterstützt gleichzeitige Abfrage mehrerer Google Cloud Antigravity-Konten. Jedes Konto zeigt separat 4 Modellkredite an, was Ihnen erleichtert, die Kreditverteilung mehrerer Projekte zu verwalten.</p><h3 id="modellzuordnungsbeziehung" tabindex="-1">Modellzuordnungsbeziehung <a class="header-anchor" href="#modellzuordnungsbeziehung" aria-label="Permalink to &quot;Modellzuordnungsbeziehung&quot;">​</a></h3><p>Google Cloud Antigravity bietet mehrere Modelle, das Plugin zeigt davon die 4 am häufigsten verwendeten:</p><table tabindex="0"><thead><tr><th>Anzeigename</th><th>Modell-Key (Haupt)</th><th>Modell-Key (Reserve)</th></tr></thead><tbody><tr><td>G3 Pro</td><td><code>gemini-3-pro-high</code></td><td><code>gemini-3-pro-low</code></td></tr><tr><td>G3 Image</td><td><code>gemini-3-pro-image</code></td><td>-</td></tr><tr><td>G3 Flash</td><td><code>gemini-3-flash</code></td><td>-</td></tr><tr><td>Claude</td><td><code>claude-opus-4-5-thinking</code></td><td><code>claude-opus-4-5</code></td></tr></tbody></table><h2 id="folgen-sie-mir" tabindex="-1">Folgen Sie mir <a class="header-anchor" href="#folgen-sie-mir" aria-label="Permalink to &quot;Folgen Sie mir&quot;">​</a></h2><h3 id="schritt-1-erstes-google-cloud-konto-hinzufugen" tabindex="-1">Schritt 1: Erstes Google Cloud-Konto hinzufügen <a class="header-anchor" href="#schritt-1-erstes-google-cloud-konto-hinzufugen" aria-label="Permalink to &quot;Schritt 1: Erstes Google Cloud-Konto hinzufügen&quot;">​</a></h3><p>Verwenden Sie das Plugin <code>opencode-antigravity-auth</code>, um ein Konto hinzuzufügen.</p><h3 id="schritt-2-google-cloud-kreditabfrage" tabindex="-1">Schritt 2: Google Cloud-Kreditabfrage <a class="header-anchor" href="#schritt-2-google-cloud-kreditabfrage" aria-label="Permalink to &quot;Schritt 2: Google Cloud-Kreditabfrage&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/mystatus</span></span></code></pre></div><h3 id="schritt-3-zweites-google-cloud-konto-hinzufugen" tabindex="-1">Schritt 3: Zweites Google Cloud-Konto hinzufügen <a class="header-anchor" href="#schritt-3-zweites-google-cloud-konto-hinzufugen" aria-label="Permalink to &quot;Schritt 3: Zweites Google Cloud-Konto hinzufügen&quot;">​</a></h3><p>Wiederholen Sie den Vorgang mit einem anderen Google-Konto.</p><h3 id="schritt-4-mehrere-kontenkredite-anzeigen" tabindex="-1">Schritt 4: Mehrere Kontenkredite anzeigen <a class="header-anchor" href="#schritt-4-mehrere-kontenkredite-anzeigen" aria-label="Permalink to &quot;Schritt 4: Mehrere Kontenkredite anzeigen&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/mystatus</span></span></code></pre></div><h2 id="haufige-fehler" tabindex="-1">Häufige Fehler <a class="header-anchor" href="#haufige-fehler" aria-label="Permalink to &quot;Häufige Fehler&quot;">​</a></h2><h3 id="konto-nicht-angezeigt" tabindex="-1">Konto nicht angezeigt <a class="header-anchor" href="#konto-nicht-angezeigt" aria-label="Permalink to &quot;Konto nicht angezeigt&quot;">​</a></h3><p>Stellen Sie sicher, dass das Konto ein <code>email</code>-Feld hat.</p><h3 id="fehlender-project-id" tabindex="-1">Fehlender Project-ID <a class="header-anchor" href="#fehlender-project-id" aria-label="Permalink to &quot;Fehlender Project-ID&quot;">​</a></h3><p>Stellen Sie sicher, dass die Konfiguration <code>projectId</code> oder <code>managedProjectId</code> enthält.</p><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><ul><li>Installation des Plugins <code>opencode-antigravity-auth</code> ist Voraussetzung für die Verwendung der Google Cloud-Kreditabfrage</li><li>Unterstützt gleichzeitige Abfrage mehrerer Konten, jedes zeigt separat 4 Modellkredite</li><li>Jedes Konto muss ein <code>email</code>-Feld enthalten</li></ul><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um die Quellcodepositionen anzuzeigen</strong></summary><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>Modellkonfiguration</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>69-78</td></tr></tbody></table></details>',28)])])}const m=t(i,[["render",r]]);export{c as __pageData,m as default};
